import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";

export interface MembershipOrder {
  id: string;
  user_id: string;
  product_id: string;
  status: string;
  apple_transaction_id: string | null;
  amount: number | null;
  currency: string | null;
  platform: string | null;
  error_message: string | null;
  restaurant_id: string | null;
  created_at: string;
  updated_at: string;
}

// Create a new membership order
export const useCreateMembershipOrder = () => {
  const queryClient = useQueryClient();
  
  return useMutation({
    mutationFn: async (params: {
      product_id: string;
      status: string;
      apple_transaction_id?: string;
      amount?: number;
      currency?: string;
      platform?: string;
      error_message?: string;
      restaurant_id?: string;
    }) => {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) throw new Error("Not authenticated");
      
      const { data, error } = await supabase
        .from("membership_orders")
        .insert({
          user_id: user.id,
          product_id: params.product_id,
          status: params.status,
          apple_transaction_id: params.apple_transaction_id || null,
          amount: params.amount || null,
          currency: params.currency || "USD",
          platform: params.platform || "ios",
          error_message: params.error_message || null,
          restaurant_id: params.restaurant_id || null,
        } as any)
        .select()
        .single();
      
      if (error) throw error;
      return data;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["membershipOrders"] });
    },
  });
};

// Update an existing membership order
export const useUpdateMembershipOrder = () => {
  const queryClient = useQueryClient();
  
  return useMutation({
    mutationFn: async (params: {
      id: string;
      status: string;
      apple_transaction_id?: string;
      error_message?: string;
    }) => {
      const { data, error } = await supabase
        .from("membership_orders")
        .update({
          status: params.status,
          apple_transaction_id: params.apple_transaction_id || undefined,
          error_message: params.error_message || undefined,
        })
        .eq("id", params.id)
        .select()
        .single();
      
      if (error) throw error;
      return data;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["membershipOrders"] });
    },
  });
};

// Get current user's membership orders
export const useMyMembershipOrders = () => {
  const { user } = useAuth();
  
  return useQuery({
    queryKey: ["membershipOrders", "my", user?.id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("membership_orders")
        .select("*")
        .order("created_at", { ascending: false });
      
      if (error) throw error;
      return data as MembershipOrder[];
    },
    enabled: !!user,
  });
};

// Admin: get all membership orders
export const useAllMembershipOrders = () => {
  return useQuery({
    queryKey: ["membershipOrders", "all"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("membership_orders")
        .select("*")
        .order("created_at", { ascending: false });
      
      if (error) throw error;
      return data as MembershipOrder[];
    },
  });
};

// Admin: archive (delete) membership orders
export const useArchiveMembershipOrders = () => {
  const queryClient = useQueryClient();
  
  return useMutation({
    mutationFn: async (orderIds: string[]) => {
      const { error } = await supabase
        .from("membership_orders")
        .delete()
        .in("id", orderIds);
      
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["membershipOrders"] });
    },
  });
};
